  1→import { describe, it, expect, vi } from 'vitest'
  2→import { screen } from '@testing-library/react'
  3→import userEvent from '@testing-library/user-event'
  4→import { renderWithMantine } from '@/test/render'
  5→import { InstitutionCard, InstitutionCardSkeleton } from './InstitutionCard'
  6→import type { SearchInstitution } from './types'
  7→
  8→const BASE_INSTITUTION: SearchInstitution = {
  9→  unitID: '166683',
 10→  name: 'Massachusetts Institute of Technology',
 11→  city: 'Cambridge',
 12→  state: 'MA',
 13→}
 14→
 15→describe('InstitutionCard', () => {
 16→  it('renders institution name, city, and state', () => {
 17→    renderWithMantine(
 18→      <InstitutionCard
 19→        institution={BASE_INSTITUTION}
 20→        hasLocation={false}
 21→        hasState={false}
 22→        onClick={() => {}}
 23→      />,
 24→    )
 25→    expect(screen.getByText('Massachusetts Institute of Technology')).toBeInTheDocument()
 26→    expect(screen.getByText('Cambridge, MA')).toBeInTheDocument()
 27→  })
 28→
 29→  it('calls onClick when clicked', async () => {
 30→    const user = userEvent.setup()
 31→    const onClick = vi.fn()
 32→    renderWithMantine(
 33→      <InstitutionCard
 34→        institution={BASE_INSTITUTION}
 35→        hasLocation={false}
 36→        hasState={false}
 37→        onClick={onClick}
 38→      />,
 39→    )
 40→    await user.click(screen.getByRole('button'))
 41→    expect(onClick).toHaveBeenCalledOnce()
 42→  })
 43→
 44→  it('calls onClick on Enter key', async () => {
 45→    const user = userEvent.setup()
 46→    const onClick = vi.fn()
 47→    renderWithMantine(
 48→      <InstitutionCard
 49→        institution={BASE_INSTITUTION}
 50→        hasLocation={false}
 51→        hasState={false}
 52→        onClick={onClick}
 53→      />,
 54→    )
 55→    screen.getByRole('button').focus()
 56→    await user.keyboard('{Enter}')
 57→    expect(onClick).toHaveBeenCalledOnce()
 58→  })
 59→
 60→  it('calls onClick on Space key', async () => {
 61→    const user = userEvent.setup()
 62→    const onClick = vi.fn()
 63→    renderWithMantine(
 64→      <InstitutionCard
 65→        institution={BASE_INSTITUTION}
 66→        hasLocation={false}
 67→        hasState={false}
 68→        onClick={onClick}
 69→      />,
 70→    )
 71→    screen.getByRole('button').focus()
 72→    await user.keyboard(' ')
 73→    expect(onClick).toHaveBeenCalledOnce()
 74→  })
 75→
 76→  it('shows distance when hasLocation is true and distance is present', () => {
 77→    const inst = { ...BASE_INSTITUTION, distance: 42.3 }
 78→    renderWithMantine(
 79→      <InstitutionCard institution={inst} hasLocation={true} hasState={false} onClick={() => {}} />,
 80→    )
 81→    expect(screen.getByTestId('distance')).toHaveTextContent('42 mi')
 82→  })
 83→
 84→  it('shows "< 1 mi" for distances under 1', () => {
 85→    const inst = { ...BASE_INSTITUTION, distance: 0.3 }
 86→    renderWithMantine(
 87→      <InstitutionCard institution={inst} hasLocation={true} hasState={false} onClick={() => {}} />,
 88→    )
 89→    expect(screen.getByTestId('distance')).toHaveTextContent('< 1 mi')
 90→  })
 91→
 92→  it('does not show distance when hasLocation is false', () => {
 93→    const inst = { ...BASE_INSTITUTION, distance: 42.3 }
 94→    renderWithMantine(
 95→      <InstitutionCard
 96→        institution={inst}
 97→        hasLocation={false}
 98→        hasState={false}
 99→        onClick={() => {}}
100→      />,
101→    )
102→    expect(screen.queryByTestId('distance')).not.toBeInTheDocument()
103→  })
104→
105→  it('shows myPrice when hasState is true and myPrice is present', () => {
106→    const inst = { ...BASE_INSTITUTION, myPrice: 15000 }
107→    renderWithMantine(
108→      <InstitutionCard institution={inst} hasLocation={false} hasState={true} onClick={() => {}} />,
109→    )
110→    expect(screen.getByTestId('my-price')).toHaveTextContent('$15,000')
111→  })
112→
113→  it('does not show myPrice when hasState is false', () => {
114→    const inst = { ...BASE_INSTITUTION, myPrice: 15000 }
115→    renderWithMantine(
116→      <InstitutionCard
117→        institution={inst}
118→        hasLocation={false}
119→        hasState={false}
120→        onClick={() => {}}
121→      />,
122→    )
123→    expect(screen.queryByTestId('my-price')).not.toBeInTheDocument()
124→  })
125→
126→  it('shows both distance and myPrice when both are available', () => {
127→    const inst = { ...BASE_INSTITUTION, distance: 10, myPrice: 25000 }
128→    renderWithMantine(
129→      <InstitutionCard institution={inst} hasLocation={true} hasState={true} onClick={() => {}} />,
130→    )
131→    expect(screen.getByTestId('distance')).toHaveTextContent('10 mi')
132→    expect(screen.getByTestId('my-price')).toHaveTextContent('$25,000')
133→  })
134→})
135→
136→describe('InstitutionCardSkeleton', () => {
137→  it('renders a skeleton placeholder', () => {
138→    renderWithMantine(<InstitutionCardSkeleton />)
139→    expect(screen.getByTestId('result-skeleton')).toBeInTheDocument()
140→  })
141→})
